import React, { useCallback, useMemo, useState } from 'react';
import { DateRangeFilter, dispatchAppToast, type DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatDate, formatVnd } from '../../../utils/formatters';
import { monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { VatListingRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bang-ke-vat-ban';
const PAGE_ID = 'baocao-bang-ke-vat-ban';

const BangKeVatBanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [rows, setRows] = useState<VatListingRow[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getVatSalesListing({ fromDate, toDate })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [fromDate, toDate, dispatch]);

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <div className={erp.field}>
            <DateRangeFilter
              label="Thời gian"
              fullWidth
              testId={`${TEST_ID}-date-range`}
              fromDate={fromDate}
              toDate={toDate}
              onChange={(v: DateRangeValue) => {
                setFromDate(v.fromDate ?? '');
                setToDate(v.toDate ?? '');
              }}
            />
          </div>
        ),
      },
    ],
    [fromDate, toDate],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Bảng kê VAT bán ra"
      titleIconClass="fas fa-percent"
      loading={loading}
      hasData={rows.length > 0}
      filterItems={filterItems}
      onLoad={handleLoad}
      exportPath="/accounting/vat-sales-listing/export-excel"
      exportParams={{ fromDate, toDate }}
      exportFilename={`BangKeVatBan-${fromDate}.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th>Số HĐ</th>
            <th>Ngày</th>
            <th>Khách hàng</th>
            <th>MST</th>
            <th className={reportStyles.colRight}>Tiền</th>
            <th className={reportStyles.colRight}>VAT</th>
            <th className={reportStyles.colRight}>Tổng</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i}>
              <td>{r.invoiceNumber}</td>
              <td>{formatDate(r.invoiceDate)}</td>
              <td>{r.customerName ?? '—'}</td>
              <td>{r.taxCode}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.subTotal)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.vatAmount)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.totalAmount)}</td>
            </tr>
          ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BangKeVatBanPage;
